object ExceptionHelpers {

  /** Root packages that are not typically relevant to Chisel user code. */
  final val packageTrimlist: Set[String] = Set("chisel3", "scala", "java", "jdk", "sun", "sbt")

  /** The object name of Chisel's internal `Builder`. */
  final val builderName: String = chisel3.internal.Builder.getClass.getName

  /** Return a stack trace element that looks like `... (someMessage)`.
    * @param message an optional message to include
    */
  def ellipsis(message: Option[String] = None): StackTraceElement =
    new StackTraceElement("..", " ", message.getOrElse(""), -1)

  private[chisel3] def getErrorLineInFile(sourceRoots: Seq[File], sl: SourceLine): List[String] = {
    def tryFileInSourceRoot(sourceRoot: File): Option[List[String]] = {
      try {
        val file = {
          val f = new File(sl.filename)
          // Absolute paths are not relative to sourceRoot.
          if (f.isAbsolute) f
          else new File(sourceRoot, sl.filename)
        }
        val lines = Source.fromFile(file).getLines()
        var i = 0
        while (i < (sl.line - 1) && lines.hasNext) {
          lines.next()
          i += 1
        }
        val line = lines.next()
        val caretLine = (" " * (sl.col - 1)) + "^"
        Some(line :: caretLine :: Nil)
      } catch {
        case scala.util.control.NonFatal(_) => None
      }
    }
    val sourceRootsWithDefault = if (sourceRoots.nonEmpty) sourceRoots else Seq(new File("."))
    // View allows us to search the directories one at a time and early out
    sourceRootsWithDefault.view.map(tryFileInSourceRoot(_)).collectFirst { case Some(value) => value }.getOrElse(Nil)
  }

  /** Utility methods that can be added to exceptions.
    */
  implicit class ThrowableHelpers(throwable: Throwable) {

    /** For an exception, mutably trim a stack trace to user code only.
      *
      * This does the following actions to the stack trace:
      *
      *   1. From the top, remove elements while the (root) package matches the packageTrimlist
      *   2. Optionally, from the bottom, remove elements until the class matches an anchor
      *   3. From the anchor (or the bottom), remove elements while the (root) package matches the packageTrimlist
      *
      * @param packageTrimlist packages that should be removed from the stack trace
      * @param anchor an optional class name at which user execution might begin, e.g., a main object
      * @return nothing as this mutates the exception directly
      */

      helpValueName = Some("<file>")
    )
  )
}

/** An [[firrtl.annotations.Annotation]] storing a function that returns a Chisel module
  * @param gen a generator function
  */
case class ChiselGeneratorAnnotation(gen: () => RawModule) extends NoTargetAnnotation with Unserializable {

  /** Run elaboration on the Chisel module generator function stored by this [[firrtl.annotations.Annotation]]
    */
  def elaborate: AnnotationSeq = (new chisel3.stage.phases.Elaborate).transform(Seq(this))
}

object ChiselGeneratorAnnotation extends HasShellOptions {

  /** Try to convert a string to a Scala type. */
  private def stringToAny(str: String): Any = {

    /* Something that looks like object creation, e.g., "Foo(42)" */
    val classPattern = "([a-zA-Z0-9_$.]+)\\((.*)\\)".r

  * @param circuit a Chisel Circuit
  */
class ChiselCircuitAnnotation private (val elaboratedCircuit: ElaboratedCircuit)
    extends NoTargetAnnotation
    with ChiselOption
    with Unserializable
    with Product
    with Serializable {
  def canEqual(that: Any): Boolean = that.isInstanceOf[ChiselCircuitAnnotation]

  override def equals(obj: Any): Boolean = obj match {
    case that: ChiselCircuitAnnotation => this.elaboratedCircuit == that.elaboratedCircuit
    case _ => false
  }

  def productArity: Int = 1

  def productElement(n: Int): Any = n match {
    case 0 => elaboratedCircuit
    case _ => throw new IndexOutOfBoundsException(s"Invalid index $n")
  }

  /* Caching the hashCode for a large circuit is necessary due to repeated queries.
   * Not caching the hashCode will cause severe performance degredations for large [[Circuit]]s.
   */
  override lazy val hashCode: Int = elaboratedCircuit.hashCode
}

object ChiselCircuitAnnotation extends scala.runtime.AbstractFunction1[ElaboratedCircuit, ChiselCircuitAnnotation] {

  def apply(elaboratedCircuit: ElaboratedCircuit): ChiselCircuitAnnotation = new ChiselCircuitAnnotation(
    elaboratedCircuit
  )
}
